const fs = require('fs');
const path = require('path');

// Scan /videos/ for video folders with captioned or final mp4s
const videosDir = '/videos';
const videos = [];

try {
  const entries = fs.readdirSync(videosDir);
  for (const entry of entries) {
    const fullPath = path.join(videosDir, entry);
    try {
      const stat = fs.statSync(fullPath);
      if (stat.isDirectory()) {
        // Look for captioned or final mp4
        const files = fs.readdirSync(fullPath);
        const captioned = files.find(f => f.endsWith('-captioned.mp4'));
        const final_ = files.find(f => f.endsWith('-final.mp4'));
        const videoFile = captioned || final_;
        if (videoFile) {
          // Look for caption text
          const captionFile = files.find(f => f.endsWith('-caption.txt'));
          let caption = '';
          if (captionFile) {
            caption = fs.readFileSync(path.join(fullPath, captionFile), 'utf-8').trim();
          }
          // Look for .md metadata
          const mdFile = files.find(f => f.endsWith('.md'));
          let title = entry.replace(/-\d{4}-\d{2}-\d{2}$/, '').replace(/-/g, ' ');
          videos.push({
            folder: entry,
            videoPath: path.join(fullPath, videoFile),
            videoFile: videoFile,
            caption: caption,
            title: title
          });
        }
      }
    } catch (e) { /* skip */ }
  }

  // Also check for standalone captioned videos in /videos/ root
  for (const entry of entries) {
    if (entry.endsWith('-captioned.mp4') && !fs.statSync(path.join(videosDir, entry)).isDirectory()) {
      const title = entry.replace('-captioned.mp4', '').replace(/-\d{4}-\d{2}-\d{2}$/, '').replace(/-/g, ' ');
      videos.push({
        folder: entry.replace('.mp4', ''),
        videoPath: path.join(videosDir, entry),
        videoFile: entry,
        caption: '',
        title: title
      });
    }
  }
} catch (e) {
  return [{ json: { skip: true, reason: 'Cannot read /videos/ directory: ' + e.message } }];
}

// Load posted tracker
const trackerPath = '/videos/pinterest-video-posted.json';
let posted = [];
try {
  posted = JSON.parse(fs.readFileSync(trackerPath, 'utf-8'));
} catch (e) { /* no tracker yet */ }

const postedFolders = new Set(posted.map(p => p.folder));
const unposted = videos.filter(v => !postedFolders.has(v.folder));

if (unposted.length === 0) {
  return [{ json: { skip: true, reason: 'No unposted videos found' } }];
}

const selected = unposted[0];
return [{ json: { skip: false, ...selected } }];

