const response = $input.first().json;
const content = response.choices[0].message.content;

let parsed;
try {
  const jsonMatch = content.match(/```(?:json)?\s*([\s\S]*?)```/);
  const jsonStr = jsonMatch ? jsonMatch[1].trim() : content.trim();
  parsed = JSON.parse(jsonStr);
} catch (e) {
  throw new Error('Failed to parse Grok response: ' + e.message);
}

return [{ json: parsed }];

const fs = require('fs');

const video = $('Find Unposted Video').first().json;
const videoPath = video.videoPath;
const fileName = video.videoFile;

// Copy video to /downloads/ for Zendriver access
const destPath = '/downloads/' + fileName;
fs.copyFileSync(videoPath, destPath);

return [{
  json: {
    filePath: destPath,
    fileName: fileName,
    folder: video.folder
  }
}];

const fs = require('fs');

const video = $('Find Unposted Video').first().json;
const grok = $('Parse Grok Response').first().json;
const cmdResult = $input.first().json;

let uploadResult = { status: 'unknown' };
try {
  uploadResult = JSON.parse(cmdResult.stdout || '{}');
} catch (e) { /* parse failed */ }

const success = uploadResult.status === 'success';

if (success) {
  // Update tracker
  const trackerPath = '/videos/pinterest-video-posted.json';
  let posted = [];
  try {
    posted = JSON.parse(fs.readFileSync(trackerPath, 'utf-8'));
  } catch (e) { /* new tracker */ }

  posted.push({
    folder: video.folder,
    title: grok.title,
    board: grok.board_name,
    postedAt: new Date().toISOString()
  });

  fs.writeFileSync(trackerPath, JSON.stringify(posted, null, 2));

  // Clean up staged video
  const stagedPath = $('Stage Video to Downloads').first().json.filePath;
  try { fs.unlinkSync(stagedPath); } catch (e) { /* ok */ }
}

return [{
  json: {
    success: success,
    folder: video.folder,
    title: grok.title,
    board: grok.board_name,
    uploadResult: uploadResult,
    stderr: cmdResult.stderr || ''
  }
}];
